import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Link } from 'react-router-dom';
import './PatientList.css';

const PatientList = () => {
    const navigate = useNavigate();
    const [patients, setPatients] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        fetchPatients();
    }, []);

    const fetchPatients = async () => {
        try {
            setLoading(true);
            const response = await axios.get('http://localhost:5000/api/patients');
            setPatients(response.data);
            setError('');
        } catch (err) {
            setError('Error fetching patients. Please try again.');
            console.error('Error:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this patient?')) {
            try {
                await axios.delete(`http://localhost:5000/api/patients/${id}`);
                setPatients(patients.filter(patient => patient._id !== id));
            } catch (err) {
                setError('Error deleting patient. Please try again.');
                console.error('Error:', err);
            }
        }
    };

    const filteredPatients = patients.filter(patient => {
        const searchString = searchTerm.toLowerCase();
        return (
            patient.name.toLowerCase().includes(searchString) ||
            patient.email.toLowerCase().includes(searchString) ||
            patient.phone.includes(searchString) ||
            (patient.address && patient.address.toLowerCase().includes(searchString))
        );
    });

    const formatDate = (dateString) => {
        const options = { year: 'numeric', month: 'long', day: 'numeric' };
        return new Date(dateString).toLocaleDateString(undefined, options);
    };

    if (loading) {
        return (
            <div className="loading">
                <h2>Loading Patients...</h2>
                <p>Please wait while we fetch the patient list.</p>
            </div>
        );
    }

    return (
        <div className="patient-list-container">
            <div className="patient-list-header">
                <h2>Patient List</h2>
                <button 
                    className="register-btn"
                    onClick={() => navigate('/add-patient')}
                >
                    Register New Patient
                </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="search-bar">
                <input
                    type="text"
                    placeholder="Search patients by name, email, phone or address..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            {filteredPatients.length === 0 ? (
                <div className="no-patients">
                    <h3>No Patients Found</h3>
                    <p>
                        {searchTerm 
                            ? 'No patients match your search criteria.' 
                            : 'There are no registered patients yet.'}
                    </p>
                </div>
            ) : (
                <div className="patient-grid">
                    {filteredPatients.map(patient => (
                        <div key={patient._id} className="patient-card">
                            <div className="patient-info">
                                <h3>{patient.name}</h3>
                                <p><strong>Email:</strong> {patient.email}</p>
                                <p><strong>Phone:</strong> {patient.phone}</p>
                                <p><strong>Age:</strong> {patient.age}</p>
                                <p><strong>Gender:</strong> {patient.gender}</p>
                                <p><strong>Address:</strong> {patient.address}</p>
                                {patient.medicalHistory && (
                                    <p><strong>Medical History:</strong> {patient.medicalHistory}</p>
                                )}
                            </div>

                            <div className="patient-actions">
                                <Link 
                                    to={`/patients/${patient._id}/appointments`}
                                    className="view-btn"
                                >
                                    View Appointments
                                </Link>
                                <Link 
                                    to={`/edit-patient/${patient._id}`}
                                    className="edit-btn"
                                >
                                    Edit
                                </Link>
                                <button
                                    onClick={() => handleDelete(patient._id)}
                                    className="delete-btn"
                                >
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default PatientList;
